// ─── BENEFICIARY OWNERSHIP MAP — SOURCE OF TRUTH ─────────────────────────────
// The trust/partner → human-beneficiary rollup behind the "Statement of Values"
// beneficiary filter. Seeded from the Year-End 2025 master workbook's
// "Ownership Map" tab and reconciled to it (every entity's beneficiary shares
// sum to ~100%).
//
// Each row is one stake: a beneficiary's effective % in an entity, held through
// a named partner/trust vehicle. A beneficiary can hold multiple stakes in the
// same entity (through different trusts) — their entity total is the sum.
//
// A stake's $ value is NOT stored here — it is always computed live as
// effPct × entityValue(entity).equityValue, so it tracks the entity snapshot in
// lib/properties/entityValues.ts.
//
// Note: the workbook's "JOHN R. SOHN 1942 TRUST → JOHN SOHN" stakes (7300 Revere
// 37.48% and 8200 Trust #4 50%) are recorded here as JOAN SOHN — a confirmed
// workbook typo. The program's canonical ownership already holds these as Joan
// R. Sohn's 1942 Trust; there is no separate "John Sohn" beneficiary.

import { entityValue } from "./entityValues";

export interface BeneficiaryStake {
  /** Entity code (matches EntityValue.entity). */
  entity: string;
  /** Legal partner / trust vehicle the beneficiary holds through. */
  partner: string;
  /** Human (or ultimate) beneficiary name. */
  beneficiary: string;
  /** Effective ownership fraction (0–1) of the entity for this stake. */
  effPct: number;
}

