function norm(s: string): string {
  return s.toLowerCase().replace(/\s+/g, " ").trim();
}

/** Distinct beneficiary display names, alphabetically. */
export function beneficiaryNames(): string[] {
  const seen = new Map<string, string>();
  for (const s of BENEFICIARY_STAKES) {
    const k = norm(s.beneficiary);
    if (!seen.has(k)) seen.set(k, s.beneficiary);
  }
  return [...seen.values()].sort((a, b) => a.localeCompare(b));
}

export interface BeneficiaryEntityLine {
  entity: string;
  entityName: string;
  propertyCode?: string;
  /** Number of distinct partner-vehicle stakes rolled into this entity line. */
  positions: number;
  /** Partner/trust vehicles the beneficiary holds through in this entity. */
  partners: string[];
  /** Summed effective % across those stakes. */
  pct: number;
  /** pct × entity equity value (0 when the entity has no equity basis). */
  value: number;
  /** Equity basis used (the entity's equity value). */
  equityBasis: number;
}

/** One beneficiary's full statement: one line per entity they hold, with their
 *  summed %, the partner vehicles, and their $ share of that entity's equity.
 *  Sorted by value descending. */
export function statementForBeneficiary(name: string): BeneficiaryEntityLine[] {
  const key = norm(name);
  const byEntity = new Map<string, BeneficiaryStake[]>();
  for (const s of BENEFICIARY_STAKES) {
    if (norm(s.beneficiary) !== key) continue;
    const arr = byEntity.get(s.entity) ?? [];
    arr.push(s);
    byEntity.set(s.entity, arr);
  }
  const lines: BeneficiaryEntityLine[] = [];
  for (const [entity, stakes] of byEntity) {
    const ev = entityValue(entity);
    const pct = stakes.reduce((s, x) => s + x.effPct, 0);
    const equityBasis = ev?.equityValue ?? 0;
    lines.push({
      entity,
      entityName: ev?.name ?? entity,
      propertyCode: ev?.propertyCode,
      positions: stakes.length,
      partners: [...new Set(stakes.map((s) => s.partner).filter(Boolean))],
      pct,
      value: pct * equityBasis,
      equityBasis,
    });
  }
  return lines.sort((a, b) => b.value - a.value);
}

/** A beneficiary's total equity value across all entities. */
export function beneficiaryTotalValue(name: string): number {
  return statementForBeneficiary(name).reduce((s, l) => s + l.value, 0);
}
